(function(){var csrfInput = document.getElementById('csrf_token');var csrfToken = csrfInput ? csrfInput.value:'';var recaptchaKeyMeta = document.querySelector('meta[name="recaptcha-site-key"]');var recaptchaKey = recaptchaKeyMeta ? recaptchaKeyMeta.content:'';const communityModal = document.getElementById('communityModal');const compareModal = document.getElementById('compareModal');window.openCommunityModal = function(e){if(e)e.preventDefault();var gd = document.getElementById('guestDisclosure');var gsv = document.getElementById('guestSuccessView');var cmv = document.getElementById('communityMainView');if(gd)gd.classList.remove('open');if(gsv)gsv.classList.remove('open');if(cmv)cmv.style.display = '';if(communityModal)communityModal.classList.add('open');document.body.style.overflow = 'hidden';setTimeout(()=>{if(!communityModal)return;const closeBtn = communityModal.querySelector('.s-modal-close');if(closeBtn)closeBtn.focus();},100);};window.closeCommunityModal = function(){if(communityModal)communityModal.classList.remove('open');document.body.style.overflow = '';};window.showGuestDisclosure = function(){var gd = document.getElementById('guestDisclosure');if(gd)gd.classList.add('open');setTimeout(()=>{if(gd)gd.scrollIntoView({behavior:'smooth',block:'nearest'});},50);};window.hideGuestDisclosure = function(){var gd = document.getElementById('guestDisclosure');if(gd)gd.classList.remove('open');};window.createGuestFromModal = async function(e){e.preventDefault();const btn = document.getElementById('btnCreateGuestModal');if(!btn)return;const original = btn.textContent;btn.disabled = true;btn.textContent = 'Creating…';let recaptchaToken = '';try{if(recaptchaKey && typeof grecaptcha !== 'undefined' && grecaptcha.execute){await new Promise(res =>grecaptcha.ready(res));recaptchaToken = await grecaptcha.execute(recaptchaKey,{action:'guest_signup'});}}catch(err){}try{const resp = await fetch('api/create_guest_account.php',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({csrf_token:csrfToken,recaptcha_token:recaptchaToken})});const data = await resp.json();if(data.success){var cmv = document.getElementById('communityMainView');var su = document.getElementById('successUsername');var gsv = document.getElementById('guestSuccessView');if(cmv)cmv.style.display = 'none';if(su)su.textContent = data.username || '';if(gsv)gsv.classList.add('open');setTimeout(()=>{window.location.href = data.redirect || 'main.php';},1500);}else{btn.disabled = false;btn.textContent = original;alert(data.error || 'Unable to create guest account. Please try again.');}}catch(err){btn.disabled = false;btn.textContent = original;alert('Connection error. Please try again.');}};window.openCompareModal = function(e){if(e)e.preventDefault();if(compareModal)compareModal.classList.add('open');document.body.style.overflow = 'hidden';};window.closeCompareModal = function(){if(compareModal)compareModal.classList.remove('open');document.body.style.overflow = '';};document.addEventListener('keydown',(e)=>{if(e.key === 'Escape'){if(communityModal && communityModal.classList.contains('open'))closeCommunityModal();if(compareModal && compareModal.classList.contains('open'))closeCompareModal();}});})();